const wf = $json.workflow || {};
const ex = $json.execution || {};
const err = ($json.execution && $json.execution.error) || $json.error || {};
const msg = err.message || 'ไม่ทราบสาเหตุ';
const when = new Date().toLocaleString('th-TH', { timeZone: 'Asia/Bangkok' });
const text =
  '🚨 n8n Workflow ล้มเหลว 🚨\n\n' +
  '📋 Workflow: ' + (wf.name || '-') + '\n' +
  '🕒 เวลา: ' + when + '\n' +
  '❌ Error: ' + msg + '\n' +
  (ex.url ? ('🔗 ดูรายละเอียด: ' + ex.url) : '');
return [{ json: { lineText: text } }];
